<?php require_once 'db.php'; $u=require_login('student'); verify_csrf(); $err=''; $tables=pdo()->query("SELECT t.*, EXISTS(SELECT 1 FROM bookings b WHERE b.table_id=t.id AND b.status='accepted' AND b.expiry_date>=CURDATE()) booked FROM library_tables t WHERE t.status<>'inactive' ORDER BY t.id")->fetchAll(); if($_SERVER['REQUEST_METHOD']==='POST'){ $tid=(int)($_POST['table_id']??0); $days=(int)($_POST['duration_days']??0); if(!isset(BOOKING_PRICES[$days])) $err='Invalid plan.'; else { $busy=pdo()->prepare("SELECT COUNT(*) FROM bookings WHERE table_id=? AND status='accepted' AND expiry_date>=CURDATE()"); $busy->execute([$tid]); if($busy->fetchColumn()) $err='This table is already booked.'; else { pdo()->prepare('INSERT INTO bookings(student_id,table_id,duration_days,amount) VALUES(?,?,?,?)')->execute([$u['id'],$tid,$days,BOOKING_PRICES[$days]]); header('Location: payment.php?booking_id='.pdo()->lastInsertId()); exit; } }} app_header('Book Table'); ?>
<h1>Select Study Table</h1><p class="error"><?=e($err)?></p><form method="post" id="bookingForm" class="card"><?=csrf_field()?><div class="plans"><label><input type="radio" name="duration_days" value="30" required> 1 Month / 30 Days — ₹800</label><label><input type="radio" name="duration_days" value="90"> 3 Months / 90 Days — ₹2200</label></div><input type="hidden" name="table_id" id="tableId"><div class="seat-map"><?php foreach($tables as $t):?><button type="button" class="seat <?= $t['booked']?'booked':'available'?>" data-id="<?=e($t['id'])?>" <?= $t['booked']?'disabled':''?>><?=e($t['table_code'])?></button><?php endforeach;?></div><button class="btn">Continue to Payment</button></form><script src="assets/js/seat-booking.js"></script><?php app_footer(); ?>
